        print(f'{self.name}: 왈왈!')

dog = Dog('바둑이')
dog.speak()

class Calculator:
    def add(self, a, b):
        return a + b

    def subtract(self, a, b):
        return a - b

    def multiply(self, a, b):
        return a * b

    def divide(self, a, b):
        if b == 0:
            print('0으로 나눌 수 없습니다')
            return None
        return a / b

calc = Calculator()
print(calc.add(10, 5))
print(calc.subtract(10, 3))
print(calc.multiply(4, 3))
print(calc.divide(10, 2))
print(calc.divide(5, 0))

