class StudentManager:
    def __init__(self):
        self.students = []

    def add_student(self, name, score):
        self.students.append({'name': name, 'score': score})

    def get_average(self):
        if not self.students:
            return 0
        total = sum(s['score'] for s in self.students)
        return total / len(self.students)

    def get_top_student(self):
        if not self.students:
            return None
        top = max(self.students, key=lambda s: s['score'])
        return top['name']

manager = StudentManager()
manager.add_student('김민준', 90)
manager.add_student('이서연', 85)
manager.add_student('박지훈', 95)
print(manager.get_average())
print(manager.get_top_student())

def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)

print(factorial(5))
print(factorial(0))
print(factorial(1))

