class Shape:
    def __init__(self, name):
        self.name = name

    def area(self):
        return 0

class Circle(Shape):
    def __init__(self, radius):
        super().__init__('원')
        self.radius = radius

    def area(self):
        return 3.14 * self.radius ** 2

class Rectangle(Shape):
    def __init__(self, width, height):
        super().__init__('직사각형')
        self.width = width
        self.height = height

    def area(self):
        return self.width * self.height

circle = Circle(5)
rect = Rectangle(4, 6)
print(f'원 넓이: {circle.area()}')
print(f'직사각형 넓이: {rect.area()}')
